code_changes.content:
[
  {
    "file": "lib/base64.c",
    "line": 202,
    "severity": "critical",
    "description": "Missing integer overflow check for size_t allocation. The removed overflow validation (checking if insize > UINT_MAX/4 on 32-bit systems) allows a large insize value to cause integer overflow in the calculation (insize + 2) / 3 * 4 + 1, resulting in a heap buffer overflow when encoding. An attacker can provide specially crafted input to cause memory corruption.",
    "fix_patch": "--- a/lib/base64.c
+++ b/lib/base64.c
@@ -199,6 +199,11 @@ static CURLcode base64_encode(const char *table64,
   if(!insize)
     insize = strlen(inputbuff);

+#if SIZEOF_SIZE_T == 4
+  if(insize > UINT_MAX/4)
+    return CURLE_OUT_OF_MEMORY;
+#endif
+
   base64data = output = malloc((insize + 2) / 3 * 4 + 1);
   if(!output)
     return CURLE_OUT_OF_MEMORY;
"
  },
  {
    "file": "lib/cookie.c",
    "line": 147,
    "severity": "high",
    "description": "Buffer boundary error in cookie_tailmatch function. The removal of the -1 offset causes an out-of-bounds memory read. When checking if a character is a dot separator in the hostname for domain matching, the code now reads one position too far to the right. This can cause a buffer over-read that may leak sensitive memory or crash the application when hostname_len is close to cookie_domain_len.",
    "fix_patch": "--- a/lib/cookie.c
+++ b/lib/cookie.c
@@ -144,7 +144,7 @@ static bool cookie_tailmatch(const char *cookie_domain,
    */
   if(hostname_len == cookie_domain_len)
     return TRUE;
-  if('.' == *(hostname + hostname_len - cookie_domain_len))
+  if('.' == *(hostname + hostname_len - cookie_domain_len - 1))
     return TRUE;
   return FALSE;
 }
"
  },
  {
    "file": "lib/vtls/openssl.c",
    "line": 963,
    "severity": "high",
    "description": "Missing NULL pointer check in passwd_callback function. The function calls strlen() on global_passwd parameter without checking if it is NULL first. When key_passwd is NULL (which can occur in normal operation as shown at line 1279), this results in a NULL pointer dereference that crashes the application.",
    "fix_patch": "--- a/lib/vtls/openssl.c
+++ b/lib/vtls/openssl.c
@@ -959,6 +959,8 @@ static int passwd_callback(char *buf, int num, int encrypting,
 {
   DEBUGASSERT(0 == encrypting);

+  if(!global_passwd)
+    return 0;
   if(!encrypting) {
     int klen = curlx_uztosi(strlen((char *)global_passwd));
     if(num > klen) {
"
  },
  {
    "file": "lib/vtls/openssl.c",
    "line": 382,
    "severity": "high",
    "description": "Potential NULL pointer dereference of X509_EXTENSION. The sk_X509_EXTENSION_value() function can return NULL if the stack contains NULL entries or for other reasons. The returned ext pointer is then used directly at line 390 in X509_EXTENSION_get_object(ext) without a NULL check, causing a NULL pointer dereference and application crash.",
    "fix_patch": "--- a/lib/vtls/openssl.c
+++ b/lib/vtls/openssl.c
@@ -380,6 +380,8 @@ void print_pubkey_info(struct Curl_easy *data, size_t certnum,
   for(i = 0; i < (int)sk_X509_EXTENSION_num(exts); i++) {
     ASN1_OBJECT *obj;
     X509_EXTENSION *ext = sk_X509_EXTENSION_value(exts, i);
+    if(!ext)
+      continue;
     BUF_MEM *biomem;
     char namebuf[128];
     BIO *bio_out = BIO_new(BIO_s_mem());
"
  },
  {
    "file": "lib/vtls/openssl.c",
    "line": 397,
    "severity": "high",
    "description": "Missing NULL check after BIO_get_mem_ptr(). The function return value is not checked before accessing biomem->data and biomem->length at lines 398-399. If BIO_get_mem_ptr() fails or returns an error, biomem will be uninitialized or invalid, leading to a NULL pointer dereference and out-of-bounds memory access.",
    "fix_patch": "--- a/lib/vtls/openssl.c
+++ b/lib/vtls/openssl.c
@@ -395,8 +395,10 @@ void print_pubkey_info(struct Curl_easy *data, size_t certnum,
     if(!X509V3_EXT_print(bio_out, ext, 0, 0))
       ASN1_STRING_print(bio_out, (ASN1_STRING *)X509_EXTENSION_get_data(ext));

     BIO_get_mem_ptr(bio_out, &biomem);
-    Curl_ssl_push_certinfo_len(data, certnum, namebuf, biomem->data,
-                               biomem->length);
+    if(biomem) {
+      Curl_ssl_push_certinfo_len(data, certnum, namebuf, biomem->data,
+                                 biomem->length);
+    }
     BIO_free(bio_out);
   }
 }
"
  }
]

